@startuml
skinparam classAttributeIconSize 0

abstract class Pizza {
  {abstract} void prepare();
  {abstract} void back();
  {abstract} void cut();
  {abstract} void box();
}

class PepperPizza
class GreakPizza
class CheesePizza

class SimpleFactory {
  Pizza createPizza();
}

class OrderPizza
class OrderPizza2
class OrderPizza3

PepperPizza --|> Pizza
GreakPizza --|> Pizza
CheesePizza --|> Pizza

SimpleFactory --> PepperPizza
SimpleFactory --> GreakPizza
SimpleFactory --> CheesePizza

SimpleFactory o-- OrderPizza2
SimpleFactory -- OrderPizza
SimpleFactory -- OrderPizza3

@enduml
